     1→// web/components/dashboard/activity-feed.tsx
     2→"use client";
     3→
     4→import { useEffect, useState, useRef } from "react";
     5→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
     6→import { Badge } from "@/components/ui/badge";
     7→import type { SSEEvent } from "@/lib/api/types";
     8→
     9→const BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
    10→
    11→const eventColors: Record<string, string> = {
    12→  release: "bg-green-100 text-green-800",
    13→  semantic_release: "bg-blue-100 text-blue-800",
    14→};
    15→
    16→function formatEvent(event: SSEEvent): string {
    17→  switch (event.type) {
    18→    case "release":
    19→      return `New release: ${event.data.version}`;
    20→    case "semantic_release":
    21→      return `Semantic release: ${event.data.version} (${event.data.status})`;
    22→    default:
    23→      return "Unknown event";
    24→  }
    25→}
    26→
    27→export function ActivityFeed() {
    28→  const [events, setEvents] = useState<SSEEvent[]>([]);
    29→  const [connected, setConnected] = useState(false);
    30→  const retryRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    31→
    32→  useEffect(() => {
    33→    let es: EventSource | null = null;
    34→
    35→    function connect() {
    36→      try {
    37→        es = new EventSource(`${BASE}/events`);
    38→
    39→        es.onopen = () => setConnected(true);
    40→
    41→        es.onmessage = (msg) => {
    42→          try {
    43→            const event = JSON.parse(msg.data) as SSEEvent;
    44→            setEvents((prev) => [event, ...prev].slice(0, 20));
    45→          } catch {
    46→            // ignore parse errors
    47→          }
    48→        };
    49→
    50→        es.onerror = () => {
    51→          setConnected(false);
    52→          es?.close();
    53→          // Retry connection after 5 seconds
    54→          retryRef.current = setTimeout(connect, 5000);
    55→        };
    56→      } catch {
    57→        setConnected(false);
    58→        retryRef.current = setTimeout(connect, 5000);
    59→      }
    60→    }
    61→
    62→    connect();
    63→
    64→    return () => {
    65→      es?.close();
    66→      if (retryRef.current) clearTimeout(retryRef.current);
    67→    };
    68→  }, []);
    69→
    70→  return (
    71→    <Card>
    72→      <CardHeader>
    73→        <CardTitle className="flex items-center gap-2">
    74→          Live Activity
    75→          <span className="relative flex h-2 w-2">
    76→            {connected ? (
    77→              <>
    78→                <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-green-400 opacity-75" />
    79→                <span className="relative inline-flex h-2 w-2 rounded-full bg-green-500" />
    80→              </>
    81→            ) : (
    82→              <span className="relative inline-flex h-2 w-2 rounded-full bg-gray-400" />
    83→            )}
    84→          </span>
    85→        </CardTitle>
    86→      </CardHeader>
    87→      <CardContent>
    88→        {events.length === 0 ? (
    89→          <p className="py-4 text-center text-sm text-muted-foreground">
    90→            Waiting for events...
    91→          </p>
    92→        ) : (
    93→          <div className="space-y-2 max-h-80 overflow-y-auto">
    94→            {events.map((event) => (
    95→              <div key={event.id} className="flex items-start gap-2 text-sm">
    96→                <Badge className={`shrink-0 text-xs ${eventColors[event.type] ?? ""}`}>
    97→                  {event.type}
    98→                </Badge>
    99→                <span className="flex-1 text-muted-foreground">{formatEvent(event)}</span>
   100→                <span className="shrink-0 text-xs text-muted-foreground">
   101→                  {new Date(event.timestamp).toLocaleTimeString()}
   102→                </span>
   103→              </div>
   104→            ))}
   105→          </div>
   106→        )}
   107→      </CardContent>
   108→    </Card>
   109→  );
   110→}
